{"content": "#!/usr/bin/env python3
"""
Pokemon Play Stream — Flask web UI
Shows live game stream + command interface for Evan's instructions.
Stream: http://localhost:9989/  (from stream.py)
Agent:  http://localhost:9876/  (pokemon-agent)
"""
import time
import threading
import json
import queue
import subprocess
from flask import Flask, render_template, Response, request, jsonify, stream_with_context

AGENT_URL = "http://localhost:9876"
STREAM_URL = "http://localhost:9989"

app = Flask(__name__)

# Thread-safe command queue (Evan's instructions → me)
command_queue = queue.Queue()

# Latest game state snapshot
game_state = {"status": "unknown", "position": None, "hp": None, "in_battle": False, "dialog": False}
state_lock = threading.Lock()

# SSE subscribers
subscribers = []

def poll_state():
    """Poll agent /state every 2 seconds, broadcast to SSE subscribers."""
    import requests
    while True:
        try:
            r = requests.get(f"{AGENT_URL}/state", timeout=3)
            if r.status_code == 200:
                data = r.json()
                with state_lock:
                    game_state["status"] = "playing" if data.get("map_id") else "idle"
                    game_state["position"] = data.get("pos")
                    game_state["hp"] = data.get("player_hp")
                    game_state["in_battle"] = data.get("battle", False)
                    game_state["dialog"] = data.get("dialog_open", False)
                    game_state["map"] = data.get("map_name", data.get("map_id"))
                broadcast(data)
        except Exception as e:
            with state_lock:
                game_state["status"] = f"error: {e}"
        time.sleep(2)

def broadcast(data):
    """Push state update to all SSE subscribers."""
    payload = f"data: {json.dumps(data)}\n\n"
    for sub in subscribers[:]:
        try:
            sub.put(payload)
        except:
            subscribers.remove(sub)

@app.template_filter("tojson")
def tojson_filter(value):
    return json.dumps(value)

def events():
    """Server-Sent Events stream for game state."""
    q = queue.Queue()
    subscribers.append(q)
    try:
        while True:
            payload = q.get(timeout=30)
            yield payload
    except queue.Empty:
        pass
    finally:
        subscribers.remove(q)

@app.route("/events")
def event_stream():
    return Response(stream_with_context(events()), mimetype="text/event-stream")

@app.route("/")
def index():
    return render_template("index.html", stream_url=STREAM_URL)

@app.route("/api/command", methods=["POST"])
def submit_command():
    """Receive Evan's plain-text instruction, queue for me to process."""
    text = request.json.get("text", "").strip()
    if text:
        command_queue.put(text)
        return jsonify({"ok": True, "queued": text})
    return jsonify({"ok": False, "error": "empty"}), 400

@app.route("/api/state")
def get_state():
    with state_lock:
        return jsonify(dict(game_state))

@app.route("/api/queue")
def get_queue():
    """Peek at queued commands without consuming them."""
    items = list(command_queue.queue)
    return jsonify({"count": len(items), "commands": items})

@app.route("/api/queue/pop", methods=["POST"])
def pop_command():
    """Pop the next command (for me / the AI agent)."""
    try:
        cmd = command_queue.get_nowait()
        return jsonify({"command": cmd})
    except queue.Empty:
        return jsonify({"command": None})

# ── Convenience proxy routes so browser can reach agent API ──────────────────
@app.route("/api/agent/<path:path>", methods=["GET", "POST"])
def agent_proxy(path):
    import requests
    url = f"{AGENT_URL}/{path}"
    if request.method == "GET":
        r = requests.get(url, timeout=5)
        return jsonify(r.json()), r.status_code
    else:
        r = requests.post(url, json=request.json, timeout=5)
        return jsonify(r.json()), r.status_code

if __name__ == "__main__":
    t = threading.Thread(target=poll_state, daemon=True)
    t.start()

    print("Pokemon Play Stream: http://localhost:5000/")
    app.run(host="0.0.0.0", port=5000, threaded=True, debug=False)", "path": "/home/Evan/pokemon-stream/play.py"}

