<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Pokemon Stream — Hermes Plays</title>
  <style>
    * { box-sizing: border-box; margin: 0; padding: 0; }

    :root {
      --bg: #0d1117;
      --surface: #161b22;
      --border: #30363d;
      --text: #e6edf3;
      --muted: #7d8590;
      --accent: #58a6ff;
      --green: #3fb950;
      --red: #f85149;
      --yellow: #d29922;
    }

    body {
      background: var(--bg);
      color: var(--text);
      font-family: 'SF Mono', 'Fira Code', 'Consolas', monospace;
      font-size: 13px;
      height: 100vh;
      display: flex;
      flex-direction: column;
    }

    header {
      background: var(--surface);
      border-bottom: 1px solid var(--border);
      padding: 8px 16px;
      display: flex;
      align-items: center;
      gap: 12px;
      flex-shrink: 0;
    }

    header .logo {
      font-size: 16px;
      font-weight: bold;
      color: var(--accent);
    }

    .status-dot {
      width: 8px; height: 8px;
      border-radius: 50%;
      background: var(--muted);
    }
    .status-dot.playing { background: var(--green); }
    .status-dot.battle  { background: var(--red); }
    .status-dot.dialog  { background: var(--yellow); }
    .status-dot.error   { background: var(--red); }

    .status-text { color: var(--muted); }

    main {
      display: flex;
      flex: 1;
      overflow: hidden;
    }

    /* ── Left: stream ─────────────────────────────────────── */
    .stream-pane {
      flex: 0 0 320px;
      border-right: 1px solid var(--border);
      display: flex;
      flex-direction: column;
      background: #000;
    }

    .stream-pane img {
      width: 320px;
      height: 288px;
      object-fit: contain;
      display: block;
      background: #000;
    }

    .stream-pane .caption {
      padding: 6px 10px;
      font-size: 11px;
      color: var(--muted);
      border-top: 1px solid var(--border);
    }

    /* ── Right: controls ───────────────────────────────────── */
    .control-pane {
      flex: 1;
      display: flex;
      flex-direction: column;
      overflow: hidden;
    }

    /* State bar */
    .state-bar {
      padding: 8px 16px;
      border-bottom: 1px solid var(--border);
      display: flex;
      gap: 20px;
      font-size: 11px;
      flex-shrink: 0;
    }
    .state-bar .field { display: flex; gap: 6px; }
    .state-bar .label { color: var(--muted); }
    .state-bar .value { color: var(--accent); }

    /* Instructions panel */
    .instr-panel {
      flex: 1;
      overflow-y: auto;
      padding: 12px 16px;
      display: flex;
      flex-direction: column;
      gap: 8px;
    }

    .instr-panel h3 {
      color: var(--muted);
      font-size: 10px;
      text-transform: uppercase;
      letter-spacing: 0.08em;
      margin-bottom: 4px;
    }

    .instr-item {
      background: var(--surface);
      border: 1px solid var(--border);
      border-radius: 6px;
      padding: 10px 12px;
    }

    .instr-item .timestamp {
      color: var(--muted);
      font-size: 10px;
      margin-bottom: 4px;
    }

    .instr-item .text {
      color: var(--text);
      font-size: 13px;
    }

    /* Input row */
    .input-row {
      padding: 10px 16px;
      border-top: 1px solid var(--border);
      display: flex;
      gap: 8px;
      flex-shrink: 0;
    }

    .input-row input {
      flex: 1;
      background: var(--surface);
      border: 1px solid var(--border);
      border-radius: 6px;
      color: var(--text);
      padding: 8px 12px;
      font-family: inherit;
      font-size: 13px;
      outline: none;
    }

    .input-row input:focus {
      border-color: var(--accent);
    }

    .input-row button {
      background: var(--accent);
      color: #000;
      border: none;
      border-radius: 6px;
      padding: 8px 16px;
      font-family: inherit;
      font-size: 13px;
      font-weight: bold;
      cursor: pointer;
    }

    .input-row button:hover { opacity: 0.85; }

    /* Status indicator */
    .connection-status {
      padding: 4px 8px;
      border-radius: 4px;
      font-size: 10px;
      font-weight: bold;
    }
    .connection-status.connected    { color: var(--green); }
    .connection-status.disconnected { color: var(--muted); }
  </style>
</head>
<body>

<header>
  <div class="logo">HERMES PLAYS POKEMON</div>
  <div class="status-dot" id="statusDot"></div>
  <span class="status-text" id="statusText">Connecting...</span>
  <div class="connection-status disconnected" id="connStatus">SSE: --</div>
</header>

<main>

  <!-- Left: game stream -->
  <div class="stream-pane">
    <img id="gameImg" src="/api/agent/screenshot" alt="Game stream">
    <div class="caption">
      Live stream · refreshes every 2s &nbsp;|&nbsp;
      <a id="directLink" href="/api/agent/screenshot" target="_blank" style="color:var(--accent)">direct PNG</a>
    </div>
  </div>

  <!-- Right: state + instructions -->
  <div class="control-pane">

    <div class="state-bar">
      <div class="field">
        <span class="label">MAP</span>
        <span class="value" id="mapLabel">—</span>
      </div>
      <div class="field">
        <span class="label">POS</span>
        <span class="value" id="posLabel">—</span>
      </div>
      <div class="field">
        <span class="label">HP</span>
        <span class="value" id="hpLabel">—</span>
      </div>
      <div class="field">
        <span class="label">BATTLE</span>
        <span class="value" id="battleLabel">—</span>
      </div>
    </div>

    <div class="instr-panel" id="instrPanel">
      <h3>Your Instructions</h3>
      <div id="instrList">
        <div class="instr-item" style="color:var(--muted); font-size:12px">
          No instructions yet. Type something below to tell Hermes what to do.
        </div>
      </div>
    </div>

    <div class="input-row">
      <input id="cmdInput" type="text" placeholder="e.g. 'go north' or 'save game as before_bulbasaur' or 'i want to fight brock'" autocomplete="off">
      <button id="sendBtn">SEND</button>
    </div>

  </div>
</main>

<script>
  // ── SSE state subscription ──────────────────────────────────────────────────
  let sseConnected = false;

  function connectSSE() {
    const es = new EventSource('/events');

    es.onmessage = (e) => {
      const data = JSON.parse(e.data);
      sseConnected = true;
      updateConnStatus();

      // Update state bar
      document.getElementById('mapLabel').textContent    = data.map_name    || data.map_id    || '—';
      document.getElementById('posLabel').textContent    = data.pos         || '—';
      document.getElementById('hpLabel').textContent     = data.player_hp   || '—';
      document.getElementById('battleLabel').textContent = data.battle      ? 'YES ⚔'         : 'no';

      // Status dot
      const dot = document.getElementById('statusDot');
      dot.className = 'status-dot';
      if (data.battle)        dot.classList.add('battle');
      else if (data.dialog_open) dot.classList.add('dialog');
      else if (data.map_id)   dot.classList.add('playing');

      document.getElementById('statusText').textContent =
        data.battle ? '⚔ IN BATTLE' :
        data.dialog_open ? '💬 DIALOG' :
        data.map_id ? 'playing' : 'idle';
    };

    es.onerror = () => {
      sseConnected = false;
      updateConnStatus();
      setTimeout(connectSSE, 3000);
    };

    es.onopen = () => {
      sseConnected = true;
      updateConnStatus();
    };
  }

  function updateConnStatus() {
    const el = document.getElementById('connStatus');
    if (sseConnected) {
      el.textContent = 'SSE: ✓';
      el.className = 'connection-status connected';
    } else {
      el.textContent = 'SSE: ✗';
      el.className = 'connection-status disconnected';
    }
  }

  connectSSE();

  // ── Image refresh ─────────────────────────────────────────────────────────
  let streamActive = true;

  function refreshImg() {
    if (streamActive) {
      const img = document.getElementById('gameImg');
      img.src = '/api/agent/screenshot?' + Date.now();
      img.onerror = () => { img.src = '/api/agent/screenshot?' + Date.now(); };
    }
    setTimeout(refreshImg, 2000);
  }
  refreshImg();

  // ── Instructions ──────────────────────────────────────────────────────────
  let myInstructions = [];

  function loadInstructions() {
    fetch('/api/queue')
      .then(r => r.json())
      .then(data => {
        if (data.count > 0 && data.commands.join(',') !== myInstructions.join(',')) {
          myInstructions = data.commands;
          renderInstructions(data.commands);
        }
      })
      .catch(() => {});
  }

  function renderInstructions(cmds) {
    const list = document.getElementById('instrList');
    if (cmds.length === 0) return;

    list.innerHTML = cmds.map((cmd, i) => `
      <div class="instr-item">
        <div class="timestamp">#${i + 1}</div>
        <div class="text">${escapeHtml(cmd)}</div>
      </div>
    `).join('');

    // Auto-scroll panel
    const panel = document.getElementById('instrPanel');
    panel.scrollTop = panel.scrollHeight;
  }

  function escapeHtml(s) {
    return s.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
  }

  // Poll queue every 2s
  setInterval(loadInstructions, 2000);

  // ── Send ─────────────────────────────────────────────────────────────────
  function sendInstruction() {
    const input = document.getElementById('cmdInput');
    const text = input.value.trim();
    if (!text) return;

    fetch('/api/command', {
      method: 'POST',
      headers: {'Content-Type': 'application/json'},
      body: JSON.stringify({text})
    })
    .then(r => r.json())
    .then(() => {
      input.value = '';
      loadInstructions();
    })
    .catch(err => alert('Failed to send: ' + err));
  }

  document.getElementById('sendBtn').addEventListener('click', sendInstruction);
  document.getElementById('cmdInput').addEventListener('keydown', (e) => {
    if (e.key === 'Enter') sendInstruction();
  });
</script>

</body>
</html>", "path": "/home/Evan/pokemon-stream/templates/index.html"}

